<div class="fr">
<svg viewBox="0 0 700 440" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Le Moi qui Planifie et le Moi qui Agit Calculent le Temps Différemment</text>
  <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Actualisation Exponentielle vs Quasi-Hyperbolique — Valeur Subjective Selon le Délai</text>
  <line x1="80" y1="70" x2="80" y2="320" stroke="#52525b" stroke-width="1.5"/>
  <line x1="80" y1="320" x2="650" y2="320" stroke="#52525b" stroke-width="1.5"/>
  <text x="60" y="80" fill="#a1a1aa" font-size="13" text-anchor="end" font-family="sans-serif">Valeur</text>
  <text x="650" y="345" fill="#a1a1aa" font-size="13" text-anchor="end" font-family="sans-serif">Délai →</text>
  <polyline points="80,70 137,107.5 194,139.4 251,166.5 308,189.5 365,209.1 422,225.7 479,239.8 536,251.9 593,262.1 650,270.8" fill="none" stroke="#4ade80" stroke-width="3"/>
